import os
base = os.getcwd()

# src/index.css
content_src_index_css = '@import url(\'https://fonts.googleapis.com/css2?family=Plus+Jakarta+Sans:wght@400;500;600;700;800;900&display=swap\');\n\n:root {\n  --bg:       #f0faf4;\n  --bg2:      #ffffff;\n  --text:     #0d2010;\n  --text2:    #5a7a5a;\n  --border:   #c8e6c9;\n  --card:     #ffffff;\n  --shadow:   0 2px 20px rgba(0,100,0,0.09);\n  --green:    #16a34a;\n  --green-lt: #22c55e;\n  --green-bg: #dcfce7;\n}\n[data-theme="dark"] {\n  --bg:       #071209;\n  --bg2:      #0f1e11;\n  --text:     #d1f0d1;\n  --text2:    #6a9a6a;\n  --border:   #1c3a1e;\n  --card:     #0f1e11;\n  --shadow:   0 2px 20px rgba(0,0,0,0.45);\n  --green:    #4ade80;\n  --green-lt: #86efac;\n  --green-bg: #14291a;\n}\n\n* { margin: 0; padding: 0; box-sizing: border-box; }\n\nbody {\n  font-family: \'Plus Jakarta Sans\', system-ui, sans-serif;\n  background: var(--bg);\n  color: var(--text);\n  transition: background 0.35s, color 0.35s;\n  min-height: 100vh;\n  -webkit-font-smoothing: antialiased;\n}\n\nbutton { cursor: pointer; border: none; font-family: inherit; outline: none; }\ninput  { font-family: inherit; outline: none; }\na      { text-decoration: none; color: inherit; }\n\n::-webkit-scrollbar { width: 6px; }\n::-webkit-scrollbar-track { background: transparent; }\n::-webkit-scrollbar-thumb { background: var(--border); border-radius: 3px; }\n\n.leaflet-container { z-index: 1; }\n'
path_src_index_css = os.path.join(base, r"src/index.css")
os.makedirs(os.path.dirname(path_src_index_css) or ".", exist_ok=True)
open(path_src_index_css, "w", encoding="utf-8").write(content_src_index_css)
print("OK: src/index.css")

# src/main.jsx
